      --title-font: 'Anton', 'Noto Serif SC', sans-serif;
      --body-font: 'Inter', 'Noto Serif SC', sans-serif;
      --font-scale: 1; /* 用于字体大小的缩放因子 */

      /* [布局变量] */
      --container-padding-desktop: 25px;
      --container-padding-mobile: 20px;
      --block-padding: 18px;
      --block-gap: 20px;
    }

    /* --- [核心优化]: 背景融合与滚动条美化 --- */
    body {
      margin: 0;
      padding: 0;
      background: transparent;
      -webkit-font-smoothing: antialiased;
      -moz-osx-font-smoothing: grayscale;
    }

    ::-webkit-scrollbar { width: 8px; }
    ::-webkit-scrollbar-track { background: rgba(0,0,0,0.3); }
    ::-webkit-scrollbar-thumb { background: var(--accent-color); border-radius: 4px; }
    ::-webkit-scrollbar-thumb:hover { background: var(--primary-color); }

    /* --- 核心容器 --- */
    .status-bar-data-container { display: none; }
    .status-bar-container {
      width: 100%;
      background: var(--background-color);
      color: var(--text-primary-color);
      font-family: var(--body-font);
      border-top: 1px solid var(--accent-color);
      border-bottom: 1px solid var(--accent-color);
      box-shadow: 0 0 35px rgba(0, 0, 0, 0.25);
      overflow: hidden;
      display: flex;
      flex-direction: column;
      min-height: 100px;
      transition: all 0.4s ease-in-out;
      border-radius: 12px; /* <--- 新增圆角 */
    }

    /* --- 头部区域 --- */
    .status-bar-header {
      padding: var(--container-padding-mobile);
      border-bottom: 1px solid var(--border-color);
      text-align: left;
      position: relative;
      cursor: pointer;
      -webkit-tap-highlight-color: transparent;
      transition: border-color 0.4s ease;
    }
    .main-title {
      font-family: var(--title-font);
      font-size: calc(2.5rem * var(--font-scale, 1));
      font-weight: 400;
      line-height: 1.1;
      text-transform: uppercase;
      letter-spacing: 1.5px;
      color: var(--text-primary-color);
      text-shadow: 0 0 8px var(--primary-color), 1px 1px 3px rgba(0,0,0,0.7);
    }
    .quote {
      font-family: 'Noto Serif SC', serif;
      font-weight: 400; font-style: normal;
      font-size: calc(0.95rem * var(--font-scale, 1));
      color: var(--text-secondary-color); margin-top: 15px;
      padding-left: 15px; border-left: 3px solid var(--primary-color);
      transition: all 0.3s ease;
    }

    /* --- 响应式内容区 --- */
    .content-area {
      flex-grow: 1;
      display: grid; grid-template-columns: 1fr;
      transition: opacity 0.4s ease-in-out, transform 0.4s ease-in-out, max-height 0.4s ease-in-out;
      will-change: opacity, transform, max-height;
    }
    .left-column, .right-column {
      display: flex; flex-direction: column;
      gap: var(--block-gap); padding: var(--container-padding-mobile);
    }
    .left-column { border-bottom: 1px solid var(--border-color); }

    /* --- 折叠状态样式 --- */
    .status-bar-container.collapsed .content-area {
      opacity: 0;
      transform: translateY(-20px);
      max-height: 0;
      overflow: hidden;
      padding-top: 0 !important;
      padding-bottom: 0 !important;
      pointer-events: none;
    }
    .status-bar-container.collapsed .status-bar-header {
      border-bottom-color: transparent;
    }
    .status-bar-container.collapsed .quote {
        max-height: 1000px;
        opacity: 1;
    }

    /* --- 底部控制栏 --- */
    .status-bar-footer {
        display: flex;
        justify-content: space-between;
        align-items: center;
        padding: 10px var(--container-padding-mobile);
        border-top: 1px solid var(--border-color);
        background: var(--button-bg-color);
        flex-shrink: 0;
        cursor: pointer;
        -webkit-tap-highlight-color: transparent;
    }

    /* 配色切换器样式 */
    .theme-switcher {
      display: flex;
      gap: 8px;
      align-items: center;
    }
    .theme-button {
      width: 20px; height: 20px;
      border-radius: 50%;
      cursor: pointer;
      border: 3px solid var(--button-outer-color, grey);
      background-color: var(--button-inner-color, black);
      box-sizing: border-box;
      transition: transform 0.2s ease, box-shadow 0.2s ease;
      flex-shrink: 0;
    }
    .theme-button:hover {
      transform: scale(1.15);
      box-shadow: 0 0 8px rgba(255, 255, 255, 0.5);
    }
    .theme-button.active {
      border-width: 4px;
      transform: scale(1.1);
      box-shadow: 0 0 10px var(--primary-color);
    }

    /* 字体大小调整器样式 */
    .font-size-adjuster {
        display: flex;
        gap: 10px;
        align-items: center;
    }
    .font-adjust-button {
        width: 28px;
        height: 28px;
        border-radius: 50%;
        background-color: transparent;
        border: 1px solid var(--text-secondary-color);
        color: var(--text-secondary-color);
        font-family: monospace;
        font-size: 1.2rem;
        cursor: pointer;
        display: flex;
        justify-content: center;
        align-items: center;
        transition: all 0.2s ease;
    }
    .font-adjust-button:hover {
        background-color: var(--primary-color);
        color: var(--text-primary-color);
        border-color: var(--primary-color);
        transform: scale(1.1);
    }

    /* --- 数据块样式 --- */
    .data-block {
      background: rgba(0, 0, 0, 0.1);
      padding: var(--block-padding); border-radius: 8px;
      border: 1px solid transparent; transition: all 0.3s ease;
      opacity: 0; animation: fadeIn 0.6s ease-out forwards;
    }
    .data-block:hover {
      border-color: var(--border-color); transform: translateY(-3px);
      box-shadow: 0 5px 15px rgba(0,0,0,0.2);
    }

    /* 动画延迟 */
    .left-column .data-block:nth-child(1) { animation-delay: 0.1s; }
    .left-column .data-block:nth-child(2) { animation-delay: 0.2s; }
    .left-column .data-block:nth-child(3) { animation-delay: 0.3s; }
    .right-column .data-block:nth-child(1) { animation-delay: 0.4s; }
    .right-column .data-block:nth-child(2) { animation-delay: 0.5s; }
    .right-column .data-block:nth-child(3) { animation-delay: 0.6s; }
    .right-column .data-block:nth-child(4) { animation-delay: 0.7s; }

    .data-block-title {
      font-family: var(--title-font);
      font-size: calc(1.2rem * var(--font-scale, 1));
      text-transform: uppercase; letter-spacing: 1px;
      color: var(--text-primary-color);
      border-bottom: 1px solid var(--border-color); padding-bottom: 10px;
      margin-bottom: 12px; display: flex; align-items: center;
    }
    .data-block-title::before {
      content: ''; display: inline-block;
      width: 10px; height: 10px;
      background-color: var(--primary-color); margin-right: 12px;
      border-radius: 3px; box-shadow: 0 0 6px var(--primary-color);
    }

    .data-item {
      display: flex; justify-content: space-between; align-items: center;
      padding: 8px 0;
      font-size: calc(0.9rem * var(--font-scale, 1));
    }
    .data-key {
      font-weight: 500; color: var(--text-secondary-color);
      flex-shrink: 0; margin-right: 15px;
    }
    .data-value {
      font-weight: 400; text-align: right;
      word-break: break-word; color: var(--text-primary-color);
    }
    .data-item.long-text-item {
      flex-direction: column; align-items: flex-start;
    }
    .data-item.long-text-item .data-value {
      text-align: left; margin-top: 6px; width: 100%; line-height: 1.6;
    }

    @keyframes fadeIn {
      from { opacity: 0; transform: translateY(20px); }
      to { opacity: 1; transform: translateY(0); }
    }

    /* --- 桌面端布局 (@media query) --- */
    @media (min-width: 800px) {
      .status-bar-header { padding: var(--container-padding-desktop); }
      .status-bar-footer { padding: 10px var(--container-padding-desktop); }
      .content-area {
        grid-template-columns: 2fr 3fr;
      }
      .left-column, .right-column { padding: var(--container-padding-desktop); }
      .left-column {
        border-right: 1px solid var(--border-color);
        border-bottom: none;
      }
      .main-title { font-size: calc(3.5rem * var(--font-scale, 1)); }
      .quote { font-size: calc(1.05rem * var(--font-scale, 1)); }
      .data-block-title { font-size: calc(1.3rem * var(--font-scale, 1)); }
      .data-item { font-size: calc(0.95rem * var(--font-scale, 1)); }
    }
  </style>
</head>
<body>

  <div class="status-bar-data-container">$1</div>

  <div class="status-bar-container">
    <header class="status-bar-header"></header>
    <main class="content-area">
      <div class="left-column"></div>
      <div class="right-column"></div>
    </main>
    <footer class="status-bar-footer"></footer>
  </div>

<script>
    (function() {
      document.addEventListener('DOMContentLoaded', () => {
        const dataContainer = document.querySelector('.status-bar-data-container');
        const container = document.querySelector('.status-bar-container');
        const headerArea = document.querySelector('.status-bar-header');
        const leftColumn = document.querySelector('.left-column');
        const rightColumn = document.querySelector('.right-column');
        const footerArea = document.querySelector('.status-bar-footer');

        if (!container || !dataContainer || !headerArea || !leftColumn || !rightColumn || !footerArea) {
          console.error('Luminaris Status Bar: Critical elements missing.');
          return;
        }

        const themes = {
          'celestial': {
            '--primary-color': '#ff4757', '--accent-color': '#c09e6d', '--background-color': '#3e000c',
            '--button-bg-color': '#000000', '--text-primary-color': '#f5ede0', '--text-secondary-color': '#b8a994',
            '--border-color': 'rgba(192, 158, 109, 0.25)'
          },
          'dark': {
            '--primary-color': '#7f5af0', '--accent-color': '#2cb67d', '--background-color': '#16161a',
            '--button-bg-color': '#242629', '--text-primary-color': '#fffffe', '--text-secondary-color': '#94a1b2',
            '--border-color': 'rgba(148, 161, 178, 0.2)'
          },
          'gray': {
            '--primary-color': '#495057', '--accent-color': '#adb5bd', '--background-color': '#dee2e6',
            '--button-bg-color': '#e9ecef', '--text-primary-color': '#212529', '--text-secondary-color': '#6c757d',
            '--border-color': 'rgba(73, 80, 87, 0.15)'
          },
          'classic-green': {
            '--primary-color': '#588157', '--accent-color': '#dad7cd', '--background-color': '#3a5a40',
            '--button-bg-color': '#588157', '--text-primary-color': '#dad7cd', '--text-secondary-color': '#a3b18a',
            '--border-color': 'rgba(218, 215, 205, 0.2)'
          },
          'ancient': {
            '--primary-color': '#8a5a44', '--accent-color': '#d4a59a', '--background-color': '#f5e7de',
            '--button-bg-color': '#e8d5b7', '--text-primary-color': '#4a3f35', '--text-secondary-color': '#8b5a2b',
            '--border-color': 'rgba(139, 90, 43, 0.15)'
          },
          'ink': {
            '--primary-color': '#3a5a40', '--accent-color': '#588157', '--background-color': '#dad7cd',
            '--button-bg-color': '#a3b18a', '--text-primary-color': '#344e41', '--text-secondary-color': '#3a5a40',
            '--border-color': 'rgba(58, 90, 64, 0.2)'
          }
        };

        let currentFontScale = 1.0;

        function initializeControls() {
            footerArea.innerHTML = '';

            const switcher = document.createElement('div');
            switcher.className = 'theme-switcher';
            Object.keys(themes).forEach(themeName => {
                const button = document.createElement('button');
                button.className = 'theme-button';
                button.dataset.theme = themeName;
                button.title = themeName;
                button.style.setProperty('--button-inner-color', themes[themeName]['--primary-color']);
                button.style.setProperty('--button-outer-color', themes[themeName]['--accent-color']);

                button.addEventListener('click', (e) => {
                    e.stopPropagation();
                    applyTheme(themeName, true);
                });
                switcher.appendChild(button);
            });

            const adjuster = document.createElement('div');
            adjuster.className = 'font-size-adjuster';
            const btnMinus = document.createElement('button');
            btnMinus.className = 'font-adjust-button';
            btnMinus.textContent = '-';
            btnMinus.title = '减小字体';
            btnMinus.addEventListener('click', (e) => { e.stopPropagation(); adjustFontSize(-0.1); });

            const btnPlus = document.createElement('button');
            btnPlus.className = 'font-adjust-button';
            btnPlus.textContent = '+';
            btnPlus.title = '增大字体';
            btnPlus.addEventListener('click', (e) => { e.stopPropagation(); adjustFontSize(0.1); });

            adjuster.appendChild(btnMinus);
            adjuster.appendChild(btnPlus);

            const spacer = document.createElement('div');

            footerArea.appendChild(switcher);
            footerArea.appendChild(spacer);
            footerArea.appendChild(adjuster);

            const savedTheme = localStorage.getItem('luminaris-theme') || 'celestial';
            applyTheme(savedTheme, false);

            const savedFontScale = parseFloat(localStorage.getItem('luminaris-font-scale')) || 1.0;
            currentFontScale = savedFontScale;
            container.style.setProperty('--font-scale', currentFontScale);

            container.classList.add('collapsed');

            headerArea.addEventListener('click', toggleCollapse);
            footerArea.addEventListener('click', toggleCollapse);
        }

        function toggleCollapse(e) {
            if (e.target.closest('.theme-switcher') || e.target.closest('.font-size-adjuster')) {
                return;
            }
            container.classList.toggle('collapsed');
        }

        function applyTheme(themeName, save = true) {
            const theme = themes[themeName];
            if (!theme) return;

            Object.keys(theme).forEach(key => {
                container.style.setProperty(key, theme[key]);
            });

            document.querySelectorAll('.theme-button').forEach(btn => {
                btn.classList.toggle('active', btn.dataset.theme === themeName);
            });

            if (save) {
                localStorage.setItem('luminaris-theme', themeName);
            }
        }

        function adjustFontSize(amount) {
            currentFontScale += amount;
            currentFontScale = Math.max(0.7, Math.min(1.5, currentFontScale));
            container.style.setProperty('--font-scale', currentFontScale);
localStorage.setItem('luminaris-font-scale', currentFontScale);
        }

        function parseData(text) {
            const data = { blocks: [] };
            const blockRegex = /\[([^\]]+)\]([\s\S]*?)\[\/\1\]/g;
            let match;

            while ((match = blockRegex.exec(text)) !== null) {
                const blockName = match[1].trim();
                if (blockName.toLowerCase() === 'config' || blockName.toLowerCase() === '本期焦点') continue;

                const blockContent = match[2].trim();
                const items = {};
                const lines = blockContent.split('\n').filter(line => line.trim() !== '');

                lines.forEach(line => {
                    const parts = line.match(/^([^:]+):\s*(.*)/);
                    if (parts && parts.length === 3) {
                        items[parts[1].trim()] = parts[2].trim();
                    }
                });
                data.blocks.push({ name: blockName, items: items });
            }
            return data;
        }

        function renderData(data) {
          leftColumn.innerHTML = '';
          rightColumn.innerHTML = '';
          headerArea.innerHTML = '';

          const coverStory = data.blocks.find(b => b.name === '封面故事');
          if (coverStory && coverStory.items) {
            const title = coverStory.items['主打标题'] || '本期焦点';
            const quote = coverStory.items['引言'] || '';
            headerArea.innerHTML = `
              <div class="main-title">${title}</div>
              <p class="quote">${quote}</p>
            `;
          } else {
            headerArea.innerHTML = `<div class="main-title">Awaiting Signal...</div><p class="quote">Your story is about to unfold.</p>`;
          }

          const blockDistribution = {
              left: ['生命体征', '核心档案', '专业评估'],
              right: ['价值分析', '圈内观察', '媒体信息', '时局变数']
          };
          const blocksMap = new Map(data.blocks.map(b => [b.name, b]));

          blockDistribution.left.forEach(name => {
              if (blocksMap.has(name)) {
                leftColumn.appendChild(createBlockElement(blocksMap.get(name)));
              }
          });
          blockDistribution.right.forEach(name => {
              if (blocksMap.has(name)) {
                rightColumn.appendChild(createBlockElement(blocksMap.get(name)));
              }
          });
        }

        function createBlockElement(blockData) {
            const blockDiv = document.createElement('div');
            blockDiv.className = 'data-block';

            const itemsHTML = Object.entries(blockData.items).map(([key, value]) => {
                const isLongText = value.length > 25 || ['时代风向', '履历亮点', '业界评价', '当前机遇', '潜在风险'].includes(key);
                const itemClass = isLongText ? 'data-item long-text-item' : 'data-item';

                return `
                  <div class="${itemClass}">
                    <span class="data-key">${key}</span>
                    <span class="data-value">${value.replace(/\n/g, '<br>')}</span>
                  </div>`;
            }).join('');

            blockDiv.innerHTML = `<div class="data-block-title">${blockData.name}</div>${itemsHTML}`;
            return blockDiv;
        }

        const rawData = dataContainer.textContent.trim();
        if (rawData) {
          try {
            const parsedData = parseData(rawData);
            renderData(parsedData);
          } catch (error) {
            console.error('Luminaris Status Bar: Failed to parse or render data.', error);
            headerArea.innerHTML = `<div class="main-title">Data Error</div><p class="quote">Failed to process incoming signal.</p>`;
          }
        } else {
            headerArea.innerHTML = `<div class="main-title">Awaiting Signal...</div><p class="quote">Your story is about to unfold.</p>`;
        }

        initializeControls();
      });
    })();
  </script>

</body>
</html>
