     .theme-switcher { display: flex; flex-wrap: wrap; gap: 6px; align-items: center; max-width: 70%; }
     .theme-button { width: 18px; height: 18px; border-radius: 50%; cursor: pointer; border: 2px solid var(--button-outer-color, grey); background-color: var(--button-inner-color, black); box-sizing: border-box; flex-shrink: 0; transition: transform 0.2s ease, box-shadow 0.2s ease; }
     .theme-button:hover { transform: scale(1.2); box-shadow: 0 0 8px rgba(255, 255, 255, 0.5); }
     .theme-button.active { border-width: 3px; transform: scale(1.1); box-shadow: 0 0 8px var(--primary-color); }
     .font-size-adjuster { display: flex; gap: 8px; flex-shrink: 0; }
     .font-adjust-button { width: 28px; height: 28px; border-radius: 50%; background-color: transparent; border: 1px solid var(--text-secondary-color); color: var(--text-secondary-color); font-family: monospace; font-size: 1.2rem; cursor: pointer; display: flex; justify-content: center; align-items: center; transition: all 0.2s ease; }
     .font-adjust-button:hover { background-color: var(--primary-color); color: var(--background-color); border-color: var(--primary-color); }

     /* --- 数据块基础样式 --- */
     .data-block { background: rgba(0,0,0,0.1); padding: var(--block-padding); border-radius: 8px; border: 1px solid transparent; transition: all 0.3s ease; animation: fadeIn 0.6s ease-out forwards; }
     .data-block:hover { background: rgba(255,255,255,0.03); border-color: var(--border-color); }
     .data-block-title { font-family: var(--title-font); font-size: calc(1.2rem * var(--font-scale)); text-transform: uppercase; color: var(--text-primary-color); border-bottom: 1px solid var(--border-color); padding-bottom: 10px; margin-bottom: 12px; display: flex; align-items: center; transition: color 0.4s ease; }
     .data-block-title::before { content: ''; display: inline-block; width: 10px; height: 10px; background-color: var(--primary-color); margin-right: 12px; border-radius: 3px; box-shadow: 0 0 6px var(--primary-color); transition: background-color 0.4s ease, box-shadow 0.4s ease; }
     .data-item { display: flex; justify-content: space-between; align-items: center; padding: 6px 0; font-size: calc(0.9rem * var(--font-scale)); }
     .data-key { font-weight: 500; color: var(--text-secondary-color); margin-right: 15px; }
     .data-value { font-weight: 400; text-align: right; color: var(--text-primary-color); }

     /* ============ 模块：舆论新闻 (Media Buzz) ============ */
     #pane-media { display: block !important; padding: var(--container-padding-mobile); }
     .news-card { position: relative; margin-bottom: 16px; padding: 14px 16px; border-radius: 4px; background: rgba(255,255,255,0.02); transition: transform 0.2s ease; border-left-width: 4px; border-left-style: solid; }
     .news-card:hover { transform: translateX(4px); }
     .news-header { display: flex; align-items: center; margin-bottom: 8px; }
     .news-type-badge { font-family: var(--title-font); font-size: calc(0.7rem * var(--font-scale)); text-transform: uppercase; padding: 2px 8px; border-radius: 3px; margin-right: 10px; }
     .news-content-body { font-size: calc(0.92rem * var(--font-scale)); line-height: 1.6; color: var(--text-primary-color); }
     .news-card.type-public { border-left-color: #3498db; } .news-card.type-public .news-type-badge { background-color: rgba(52,152,219,0.15); color: #6bb9f0; }
     .news-card.type-private { border-left: 6px double #9b59b6; } .news-card.type-private .news-type-badge { color: #cfa5e3; border: 1px dashed rgba(155,89,182,0.4); } .news-card.type-private .news-content-body { font-style: italic; }
     .news-card.type-rumor { border-left: 4px dashed #e67e22; } .news-card.type-rumor .news-type-badge { background-color: #e67e22; color: #000; } .news-card.type-rumor .news-content-body { font-family: var(--mono-font); }

     /* ============ 模块：行动建议 (Actions) ============ */
     #pane-action { display: grid !important; grid-template-columns: 1fr; gap: 15px; padding: var(--container-padding-mobile); }
     .action-card { background: rgba(255,255,255,0.03); border: 1px solid var(--border-color); border-radius: 8px; padding: 20px; cursor: pointer; position: relative; overflow: hidden; transition: all 0.3s cubic-bezier(0.25, 0.8, 0.25, 1); display: flex; flex-direction: column; justify-content: space-between; }
     .action-card:hover { background: var(--action-bg-hover); border-color: var(--primary-color); transform: translateY(-3px) scale(1.01); box-shadow: 0 8px 20px rgba(0, 0, 0, 0.3); }
     .action-header { display: flex; justify-content: space-between; align-items: flex-start; margin-bottom: 12px; }
     .action-title { font-family: var(--title-font); font-size: calc(1.3rem * var(--font-scale)); color: var(--text-primary-color); letter-spacing: 0.5px; }
     .action-cost-badge { font-size: 0.75rem; padding: 4px 8px; border-radius: 4px; background: rgba(255,255,255,0.05); color: var(--text-secondary-color); border: 1px solid rgba(255,255,255,0.1); white-space: nowrap; pointer-events: none; }
     .action-desc { font-size: calc(0.9rem * var(--font-scale)); color: var(--text-secondary-color); line-height: 1.5; margin-bottom: 15px; flex-grow: 1; pointer-events: none; }
     .action-corner { position: absolute; bottom: 0; right: 0; width: 0; height: 0; border-style: solid; border-width: 0 0 20px 20px; border-color: transparent transparent var(--border-color) transparent; transition: border-color 0.3s; }
     .action-card:hover .action-corner { border-color: transparent transparent var(--primary-color) transparent; }

     /* ============ 核心升级：后宫概览 (Harem) V2 ============ */
     #pane-harem { display: block !important; padding: var(--container-padding-mobile); }
     .harem-section-title { font-family: var(--title-font); font-size: calc(1.5rem * var(--font-scale)); color: var(--primary-color); text-transform: uppercase; margin-bottom: 20px; padding-bottom: 10px; border-bottom: 2px solid var(--primary-color); letter-spacing: 1px; }
     .lover-card, .mother-card { background: rgba(0,0,0,0.1); border: 1px solid var(--border-color); border-radius: 8px; padding: 15px; margin-bottom: 20px; transition: all .3s ease; overflow: hidden; }
     .lover-card:hover, .mother-card:hover { transform: translateY(-3px); box-shadow: 0 4px 15px rgba(0,0,0,0.2); border-color: var(--primary-color); }
     .lover-header, .mother-header { display: flex; align-items: center; justify-content: space-between; margin-bottom: 15px; }
     .lover-name, .mother-name { font-family: var(--title-font); font-size: calc(1.3rem * var(--font-scale)); color: var(--text-primary-color); }
     .relationship-tag { background: var(--primary-color); color: var(--background-color, #fff); font-size: 0.7rem; padding: 4px 10px; border-radius: 4px; font-weight: 600; text-transform: uppercase; white-space: nowrap; }
     .affection-bar-container { background-color: rgba(0,0,0,0.3); border-radius: 5px; height: 10px; margin-bottom: 15px; overflow: hidden; border: 1px solid var(--border-color); }
     .affection-progress { height: 100%; background: var(--primary-color); border-radius: 4px; transition: width 0.5s ease-out; box-shadow: 0 0 8px var(--primary-color); }
     .lover-desc { font-size: calc(0.9rem * var(--font-scale)); color: var(--text-secondary-color); line-height: 1.5; margin-bottom: 15px; }
     .lover-stats-grid { display: grid; grid-template-columns: repeat(auto-fit, minmax(100px, 1fr)); gap: 10px; margin-bottom: 15px; padding-top: 10px; border-top: 1px dashed var(--border-color); font-size: calc(0.85rem * var(--font-scale)); }
     .stat-item { display: flex; align-items: center; gap: 8px; }
     .stat-item-label { color: var(--text-secondary-color); }
     .stat-item-value { font-weight: bold; color: var(--text-primary-color); }
     .positions-section { margin-top: 10px; }
     .positions-title { font-weight: bold; color: var(--text-secondary-color); margin-bottom: 8px; font-size: calc(0.8rem * var(--font-scale)); text-transform: uppercase;}
     .positions-container { display: flex; gap: 8px; overflow-x: auto; padding-bottom: 10px; }
     .position-tag { flex-shrink: 0; background: rgba(0,0,0,0.2); border: 1px solid var(--border-color); color: var(--text-secondary-color); padding: 5px 12px; border-radius: 15px; font-size: calc(0.8rem * var(--font-scale)); cursor: default; }
     .children-list { margin-top: 15px; padding-top: 15px; border-top: 1px dashed var(--border-color); }
     .child-entry { display: flex; justify-content: space-between; align-items: center; padding: 8px 0; border-bottom: 1px solid rgba(255,255,255,0.05); }
     .child-entry:last-child { border-bottom: none; }
     .child-name { font-weight: 600; font-size: calc(1rem * var(--font-scale)); }
     .child-details { font-size: calc(0.85rem * var(--font-scale)); color: var(--text-secondary-color); text-align: right; }

     /* === 主题覆盖逻辑 === */
     [data-active-tab="academic"] { --primary-color: #7f5af0; --accent-color: #2cb67d; --background-color: '#16161a'; --text-primary-color: '#fffffe'; --text-secondary-color: '#94a1b2'; --border-color: rgba(148, 161, 178, 0.2); }
     [data-active-tab="harem"] { --primary-color: #ff9a9e; --accent-color: #fecfef; --background-color: '#fff0f5'; --text-primary-color: '#e91e63'; --text-secondary-color: '#f06292'; --border-color: rgba(255, 154, 158, 0.4); }
     [data-active-tab="media"] { --primary-color: #3a5a40; --accent-color: #588157; --background-color: '#dee2e6'; --text-primary-color: '#2d3436'; --text-secondary-color: '#636e72'; --border-color: rgba(45, 52, 54, 0.15); --button-bg-color: '#dfe6e9'; }
     [data-active-tab="action"] { --primary-color: #ff0055; --accent-color: #00f0ff; --background-color: '#050505'; --text-primary-color: '#ffffff'; --text-secondary-color: '#8b9bb4'; --border-color: rgba(0, 240, 255, 0.3); --action-bg-hover: rgba(255, 0, 85, 0.1); }

     /* 响应式适配 */
     @media (min-width: 800px) {
        .status-bar-header, .left-column, .right-column, .status-bar-footer, #pane-media, #pane-action, #pane-harem { padding: var(--container-padding-desktop); }
        .status-bar-tabs { padding: 0 var(--container-padding-desktop); }
        .tab-pane:not(#pane-media):not(#pane-action):not(#pane-harem) { grid-template-columns: 2fr 3fr; }
        #pane-action { grid-template-columns: 1fr 1fr; gap: 25px; }
        .left-column { border-right: 1px solid var(--border-color); border-bottom: none; }
        .main-title { font-size: calc(3.5rem * var(--font-scale)); }
        .tab-button { font-size: calc(1.0rem * var(--font-scale)); }
     }
    </style>
  </head>
  <body>
    <div class="status-bar-container" data-active-tab="entertainment">
      <header class="status-bar-header"></header>
      <nav class="status-bar-tabs"></nav>
      <main class="content-area"></main>
      <footer class="status-bar-footer"></footer>
    </div>

  <script>
      (function() {
        // ======================== 数据源 ========================
$1
        const themes = { 'celestial': { '--primary-color': '#ff4757', '--accent-color': '#c09e6d', '--background-color': '#3e000c', '--button-bg-color': '#000000', '--text-primary-color': '#f5ede0', '--text-secondary-color': '#b8a994' }, 'dark': { '--primary-color': '#7f5af0', '--accent-color': '#2cb67d', '--background-color': '#16161a', '--button-bg-color': '#242629', '--text-primary-color': '#fffffe', '--text-secondary-color': '#94a1b2' }, 'ink': { '--primary-color': '#3a5a40', '--accent-color': '#588157', '--background-color': '#dad7cd', '--button-bg-color': '#a3b18a', '--text-primary-color': '#344e41', '--text-secondary-color': '#3a5a40' }, 'ocean': { '--primary-color': '#00d2ff', '--accent-color': '#3a7bd5', '--background-color': '#0f2027', '--button-bg-color': '#203a43', '--text-primary-color': '#e0f7fa', '--text-secondary-color': '#81d4fa' }, 'sakura': { '--primary-color': '#ff9a9e', '--accent-color': '#fecfef', '--background-color': '#fff0f5', '--button-bg-color': '#ffe4e1', '--text-primary-color': '#e91e63', '--text-secondary-color': '#f06292' }, 'cyber': { '--primary-color': '#fce043', '--accent-color': '#fbcb2d', '--background-color': '#111111', '--button-bg-color': '#333333', '--text-primary-color': '#ffff00', '--text-secondary-color': '#e0e0e0' }, 'latte': { '--primary-color': '#8d6e63', '--accent-color': '#d7ccc8', '--background-color': '#3e2723', '--button-bg-color': '#4e342e', '--text-primary-color': '#efebe9', '--text-secondary-color': '#bcaaa4' }, 'forest': { '--primary-color': '#2e7d32', '--accent-color': '#a5d6a7', '--background-color': '#1b5e20', '--button-bg-color': '#2e7d32', '--text-primary-color': '#e8f5e9', '--text-secondary-color': '#c8e6c9' }, 'mono': { '--primary-color': '#ffffff', '--accent-color': '#999999', '--background-color': '#000000', '--button-bg-color': '#222222', '--text-primary-color': '#ffffff', '--text-secondary-color': '#aaaaaa' } };
        let currentFontScale = 1.0;

        document.addEventListener('DOMContentLoaded', () => {
          const container = document.querySelector('.status-bar-container');
          const headerArea = document.querySelector('.status-bar-header');
          const tabsArea = document.querySelector('.status-bar-tabs');
          const contentArea = document.querySelector('.content-area');
          const footerArea = document.querySelector('.status-bar-footer');
          if (!container) return;

          function initialize() {
            renderAll(statusBarData, { tabsArea, contentArea, headerArea });
            initControls({ footerArea, container, headerArea });
            // **INIT**: Initialize action click listeners
            setupActionListeners();
            const firstTabId = Object.keys(statusBarData.tabs)[0];
            if (firstTabId) switchTab(firstTabId, tabsArea.querySelector('.tab-button'), { container, contentArea, tabsArea });
          }

          function renderAll(data, elements) {
            elements.headerArea.innerHTML = `<div class="main-title">${data.header.title||''}</div><p class="quote">${data.header.quote||''}</p>`;
            elements.tabsArea.innerHTML = '';
            elements.contentArea.innerHTML = '';

            for (const tabId in data.tabs) {
              const tabInfo = data.tabs[tabId];
              const btn = document.createElement('button');
              btn.className = 'tab-button';
              btn.textContent = tabInfo.name;
              btn.dataset.tabId = tabId;
              btn.onclick = () => switchTab(tabId, btn, { container, contentArea, tabsArea });
              elements.tabsArea.appendChild(btn);

              const pane = document.createElement('div');
              pane.className = 'tab-pane';
              pane.id = `pane-${tabId}`;

              switch (tabInfo.type) {
                case 'blocks': pane.innerHTML = renderBlocksPane(tabInfo.data); break;
                case 'news': pane.innerHTML = renderNewsPane(tabInfo.data); break;
                case 'actions': pane.innerHTML = renderActionsPane(tabInfo.data); break;
                case 'harem': pane.innerHTML = renderHaremPane(tabInfo.data); break;
              }
              elements.contentArea.appendChild(pane);
            }
          }

         function renderBlocksPane(blocks) {
             const half = Math.ceil(blocks.length / 2);
             const lCol = blocks.slice(0, half).map(b => `<div class="data-block"><div class="data-block-title">${b.name}</div>${Object.entries(b.items).map(([k,v])=>`<div class="data-item"><span class="data-key">${k}</span><span class="data-value">${v}</span></div>`).join('')}</div>`).join('');
             const rCol = blocks.slice(half).map(b => `<div class="data-block"><div class="data-block-title">${b.name}</div>${Object.entries(b.items).map(([k,v])=>`<div class="data-item"><span class="data-key">${k}</span><span class="data-value">${v}</span></div>`).join('')}</div>`).join('');
             return `<div class="left-column">${lCol}</div><div class="right-column">${rCol}</div>`;
         }

          function renderNewsPane(items) { return items.map(i => `<div class="news-card type-${{'公开':'public','非公开':'private','未证实':'rumor'}[i.type]}"><div class="news-header"><span class="news-type-badge">${{'公开':'Public','非公开':'Insider','未证实':'Rumor'}[i.type]}</span></div><div class="news-content-body">${i.content}</div></div>`).join(''); }

          // **MODIFICATION**: ACTION PANE RENDERING UPDATE
          // Added 'data-cost' attribute to collect risk/reward information.
          function renderActionsPane(items) {
            return items.map(i => `<div class="action-card" data-title="${i.title}" data-desc="${i.desc}" data-cost="${i.cost}">
                <div class="action-header">
                  <span class="action-title">${i.title}</span>
                  <span class="action-cost-badge">${i.cost}</span>
                </div>
                <div class="action-desc">${i.desc}</div>
                <div class="action-corner"></div>
              </div>`).join('');
          }

          function renderHaremPane(data) {
            let html = '';
            if(data.lovers?.length) {
              html += `<div class="harem-section-title">Lovers</div>` + data.lovers.map(l => `
                 <div class="lover-card">
                     <div class="lover-header"><span class="lover-name">${l.name}</span><span class="relationship-tag">${l.relationshipStage}</span></div>
                     <div class="affection-bar-container"><div class="affection-progress" style="width: ${l.affection}%;"></div></div>
                     <p class="lover-desc">${l.desc}</p>
                     <div class="lover-stats-grid">
                         <div class="stat-item"><span class="stat-item-label">Độ hảo cảm:</span><span class="stat-item-value">${l.affection}</span></div>
                         <div class="stat-item"><span class="stat-item-label">Số lần ân ái:</span><span class="stat-item-value">${l.encounterCount}</span></div>
                     </div>
                     <div class="positions-section">
                         <div class="positions-title">Tư thế đã mở khóa</div>
                         <div class="positions-container">${l.positions.map(p => `<span class="position-tag">${p}</span>`).join('')}</div>
                     </div>
                 </div>`).join('');
            }
            if(data.progeny?.length) {
              html += `<div class="harem-section-title">Progeny</div>` + data.progeny.map(f => `
                 <div class="mother-card">
                     <div class="mother-header"><span class="mother-name">${f.mother}</span></div>
                     <div class="children-list">${f.children.map(c => `<div class="child-entry"><span class="child-name">${c.name}</span><span class="child-details">Tuổi: ${c.age} | ${c.details}</span></div>`).join('')}</div>
                 </div>`).join('');
            }
            return html;
          }

          function switchTab(tabId, btn, { container, contentArea, tabsArea }) {
            container.dataset.activeTab = tabId;
            tabsArea.querySelectorAll('.tab-button').forEach(b => b.classList.remove('active'));
            if (btn) btn.classList.add('active');
            contentArea.querySelectorAll('.tab-pane').forEach(p => p.classList.remove('active'));
            const target = document.getElementById(`pane-${tabId}`);
            if (target) target.classList.add('active');
          }

          function initControls({ footerArea, container, headerArea }) {
            footerArea.innerHTML = '';
            const switcher = document.createElement('div'); switcher.className = 'theme-switcher';
            Object.keys(themes).forEach(k => {
              const b = document.createElement('button'); b.className = 'theme-button'; b.dataset.theme = k; b.title = k;
              b.style.setProperty('--button-inner-color', themes[k]['--primary-color']);
              b.style.setProperty('--button-outer-color', themes[k]['--accent-color']);
              b.onclick = (e) => { e.stopPropagation(); applyTheme(k, { container }); };
              switcher.appendChild(b);
            });
            const adj = document.createElement('div'); adj.className = 'font-size-adjuster';
            adj.append(...['-','+'].map(txt => { const b = document.createElement('button'); b.className = 'font-adjust-button'; b.textContent = txt; b.onclick = (e) => { e.stopPropagation(); setFont(txt === '+' ? 0.1 : -0.1, { container }); }; return b; }));
            footerArea.append(switcher, adj);
            footerArea.onclick = (e) => { if(!e.target.closest('.theme-switcher,.font-size-adjuster')) container.classList.toggle('collapsed'); };
            headerArea.onclick = () => container.classList.toggle('collapsed');
            applyTheme(localStorage.getItem('luminaris-theme') || 'celestial', { container });
            container.classList.add('collapsed');
          }

          // **MODIFICATION**: NEW LISTENER LOGIC
          // Updates now retrieve 'data-cost' and include it in the slash command.
          function setupActionListeners() {
             const contentArea = document.querySelector('.content-area');
             contentArea.addEventListener('click', (event) => {
                 const actionCard = event.target.closest('.action-card');
                 if (!actionCard) return;

                 const title = actionCard.dataset.title;
                 const desc = actionCard.dataset.desc;
                 const cost = actionCard.dataset.cost; // Retrieve cost data

                 if (title && desc) {
                     // Included 'cost' in the message body
                     const command = `/setinput [Hành động：${title}] ${desc} 【${cost}】`;

                     if (typeof triggerSlash === 'function') {
                         triggerSlash(command);
                     } else {
                         console.warn("未找到 'triggerSlash' 函数。准备发送的指令: ", command);
                     }
                 }
             });
          }

          function applyTheme(name, { container }) {
            if (!themes[name]) return;
            const t = themes[name];
            Object.keys(t).forEach(key => {
              container.style.setProperty(key, t[key]);
            });
            const borderVar = themes[name]['--border-color'] || 'rgba(192, 158, 109, 0.25)';
            container.style.setProperty('--border-color', borderVar);
            document.querySelectorAll('.theme-button').forEach(b => b.classList.toggle('active', b.dataset.theme === name));
            localStorage.setItem('luminaris-theme', name);
          }

          function setFont(delta, { container }) {
            currentFontScale = Math.max(0.7, Math.min(1.5, currentFontScale + delta));
            container.style.setProperty('--font-scale', currentFontScale);
          }

          initialize();
        });
      })();
    </script>
  </body>
  </html>
 ```
